INSERT INTO workshops (id, title, chef, level, price, max_capacity, category, emoji, image, description) VALUES
(1, 'โครยซองต์ มาสเตอร์คลาส',      'เชฟ พงศธร',  'ระดับกลาง', 3500, 12, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1555507036-ab1f4038808a?auto=format&fit=crop&w=600&q=80', 'เรียนรู้ความลับของเลเยอร์ที่สมบูรณ์แบบและการนวดเนยสไตล์ฝรั่งเศสขนานแท้'),
(2, 'เวิร์กชอปโดนัทเคลือบน้ำตาล', 'เชฟ นภัสสร', 'เริ่มต้น',   2800, 15, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'สนุกกับการปั้นและเคลือบโดนัทหลากรสชาติ พร้อมเทคนิคการทอดให้ฟูนุ่ม'),
(3, 'ขนมปังซาวร์โดว์เบื้องต้น',    'เชฟ ธนวัฒน์', 'เริ่มต้น',  2500, 10, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1549931319-a545dcf3bc73?auto=format&fit=crop&w=600&q=80', 'เริ่มต้นทำขนมปังซาวร์โดว์ตั้งแต่การเลี้ยงหัวเชื้อจนถึงการอบให้ได้เปลือกกรอบ'),
(4, 'ห้องปฏิบัติการมาการอง',        'เชฟ ปาริชาต', 'ระดับกลาง', 4200, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1569864358642-9d1684040f43?auto=format&fit=crop&w=600&q=80', 'ฝึกทำมาการองฝรั่งเศสให้ได้ผิวเรียบ เท้าสวย พร้อมไส้ครีมหลากรส'),
(5, 'พรีเมียมคัพเค้กและบัตเตอร์ครีมดอกไม้', 'เชฟ นภัสสร', 'เริ่มต้น',   3000, 12, 'เค้กและขนมหวาน',     '🧁', 'https://images.unsplash.com/photo-1576618148400-f54bed99fcfd?auto=format&fit=crop&w=600&q=80', 'เรียนรู้การอบคัพเค้กเนื้อนุ่มและเทคนิคการบีบบัตเตอร์ครีมดอกไม้สไตล์พรีเมียม'),
(6, 'มาสเตอร์คลาสครัวซองต์ช็อกโกแลตทูโทน', 'เชฟ พงศธร', 'ระดับกลาง', 3800, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1608198093002-ad4e005484ec?auto=format&fit=crop&w=600&q=80', 'ต่อยอดจากครัวซองต์คลาสสิก สู่การทำแป้งช็อกโกแลตทูโทนและสอดไส้ช็อกโกแลตพรีเมียม'),
(7, 'พรีเมียมบับก้าช็อกโกแลตโฮมเมด', 'เชฟ ธนวัฒน์', 'ระดับกลาง', 3100, 12, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&w=600&q=80', 'ทำขนมปังถัก Babka ไส้ช็อกโกแลตเบลเยียมเข้มข้น แป้งเหนียวนุ่มชุ่มฉ่ำเนย'),
(8, 'ขนมปังฟอกาชเชียสมุนไพรอิตาเลียน', 'เชฟ ธนวัฒน์', 'เริ่มต้น',   2200, 15, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1573140247632-f8fd74997d5c?auto=format&fit=crop&w=600&q=80', 'สนุกกับการตกแต่งหน้าขนมปังฟอกาชเชียด้วยสมุนไพรสด มะเขือเทศเชอร์รี และน้ำมันมะกอกเกรดพรีเมียม'),
(9, 'โดนัทสไตล์ญี่ปุ่นครีมสดวานิลลา', 'เชฟ นภัสสร', 'เริ่มต้น',   2900, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1527515637462-cff94eecc1ac?auto=format&fit=crop&w=600&q=80', 'ตีครีมสดสไตล์ญี่ปุ่น ยัดไส้โดนัทนมสดเนื้อเบานุ่มละลายในปาก'),
(10, 'ชีสเค้กหน้าไหม้สไตล์บาสก์เข้มข้น', 'เชฟ ปาริชาต', 'เริ่มต้น',   3200, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1524351199679-46cddf530c04?auto=format&fit=crop&w=600&q=80', 'อบชีสเค้กหน้าไหม้เนื้อครีมชีสเนียนนุ่มกึ่งลาวา พร้อมซอสเบอร์รีโฮมเมด'),
(11, 'คลาสสิกฟรุตทาร์ตสไตล์ฝรั่งเศส', 'เชฟ พงศธร', 'ระดับกลาง', 3400, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1519915028121-7d3463d20b13?auto=format&fit=crop&w=600&q=80', 'ทำแป้งทาร์ตกรอบร่วนสไตล์ฝรั่งเศส (Pâte Sablée) ครีมคัสตาร์ดวานิลลาแท้และผลไม้สด'),
(12, 'ขนมปังบริยอชเนยสดฝรั่งเศส', 'เชฟ ธนวัฒน์', 'ระดับกลาง', 2800, 12, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1607958996333-41aef7caefaa?auto=format&fit=crop&w=600&q=80', 'เรียนรู้วิธีนวดแป้งผสมเนยสดแท้สไตล์ Brioche Nanterre ให้ได้เนื้อสัมผัสใยไหมฉีกมือหอมละมุน'),
(13, 'ขนมปังเบเกิลสไตล์นิวยอร์ก', 'เชฟ ธนวัฒน์', 'เริ่มต้น',   2400, 12, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1585478259715-876acc5be8eb?auto=format&fit=crop&w=600&q=80', 'ฝึกทำเบเกิลเนื้อหนุบหนับตามแบบฉบับนิวยอร์กแท้ ตั้งแต่การต้มแป้งจนถึงการอบโรยงาและกระเทียม'),
(14, 'ขนมปังนมฮอกไกโดและโชกุปัง', 'เชฟ ธนวัฒน์', 'เริ่มต้น',   2600, 12, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&w=600&q=80', 'สัมผัสความนุ่มยืดแบบ Yudane เคล็ดลับขนมปังนมฮอกไกโดและโชกุปังแสนอร่อย'),
(15, 'บาแก็ตฝรั่งเศสแบบดั้งเดิม', 'เชฟ ธนวัฒน์', 'ระดับกลาง', 2300, 15, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1549931319-a545dcf3bc73?auto=format&fit=crop&w=600&q=80', 'ฝึกอบบาแก็ตฝรั่งเศสแท้ๆ (Baguette de Tradition) ให้เปลือกนอกบางกรอบ เนื้อในนุ่มเป็นโพรงสวย'),
(16, 'ซีบัคธอร์นซาวร์โดว์และธัญพืช', 'เชฟ ธนวัฒน์', 'ระดับสูง',  2700, 10, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1555507036-ab1f4038808a?auto=format&fit=crop&w=600&q=80', 'ยกระดับซาวร์โดว์ด้วยผลซีบัคธอร์นเปรี้ยวอมหวาน และธัญพืชโฮลเกรนคั่วหอมหลากชนิด'),
(17, 'ขนมปังไรย์เยอรมันคลาสสิก', 'เชฟ ธนวัฒน์', 'ระดับกลาง', 2500, 12, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&w=600&q=80', 'ขนมปังไรย์สไตล์เยอรมันแท้เนื้อแน่น เสริมสุขภาพด้วยเมล็ดฟักทองและดอกทานตะวัน'),
(18, 'ซินนามอนโรลเคลือบครีมชีสฟรอสติ้ง', 'เชฟ นภัสสร', 'เริ่มต้น',   2600, 15, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&w=600&q=80', 'ทำขนมปังซินนามอนโรลหอมอบเชยเนื้อฉ่ำ นุ่มนวล เคลือบด้วยครีมชีสฟรอสติ้งเข้มข้นรสเลิศ'),
(19, 'บอมโบโลนีโดนัทอิตาเลียนไส้คัสตาร์ด', 'เชฟ นภัสสร', 'เริ่มต้น',   3100, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'ฝึกปั้นและทอดบอมโบโลนี (Bomboloni) โดนัทกลมไม่มีรูสไตล์อิตาลี คลุกน้ำตาลทรายและบีบไส้ครีมคัสตาร์ดเนียนละมุน'),
(20, 'โดนัทเค้กช็อกโกแลตสไตล์โบราณ', 'เชฟ นภัสสร', 'เริ่มต้น',   2500, 15, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'โดนัทช็อกโกแลตเนื้อแน่นแบบ Old Fashioned รสเข้มข้น กรอบนอก นุ่มหนึบด้านใน'),
(21, 'ชูร์โรสสเปนและซอสดาร์กช็อกโกแลต', 'เชฟ พงศธร', 'เริ่มต้น',   2600, 15, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1628113315857-c81216d00465?auto=format&fit=crop&w=600&q=80', 'บีบและทอดปาท่องโก๋สเปน (Churros) ให้เหลืองทอง กรอบอร่อย คลุกอบเชยน้ำตาล และทำดิปร้อนดาร์กช็อกโกแลตแท้'),
(22, 'ครอฟเฟิลและโมจิโดนัทสองรสชาติ', 'เชฟ นภัสสร', 'เริ่มต้น',   2800, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'ผสมผสานครัวซองต์วาฟเฟิลสไตล์ฮิต และทำโดนัทแป้งโมจิหนุบหนับสไตล์ญี่ปุ่นเคลือบมัทฉะและสตรอว์เบอร์รี'),
(23, 'โดนัทเคลือบเมเปิ้ลเบคอนเค็มหวาน', 'เชฟ นภัสสร', 'ระดับกลาง', 3000, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'ทำโดนัทเคลือบไซรัปเมเปิ้ลโรยด้วยเบคอนกรอบคั่ว รสสัมผัสเค็มหวานเข้ากันอย่างลงตัวแบบคาเฟ่อเมริกา'),
(24, 'บริยอชโดนัทไส้เลมอนเคิร์ด', 'เชฟ ปาริชาต', 'ระดับกลาง', 3200, 10, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'สร้างสรรค์โดนัทพรีเมียมจากแป้งบริยอชหอมเนย สอดไส้ครีมเลมอนเคิร์ดเปรี้ยวอมหวาน หอมผิวเลมอนเหลืองสดชื่น'),
(25, 'สตรูปวาฟเฟิลสไตล์ดัตช์ดั้งเดิม', 'เชฟ นภัสสร', 'ระดับกลาง', 2700, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'ทำวาฟเฟิลแผ่นบางเฉียบสไตล์เนเธอร์แลนด์ (Stroopwafel) รีดร้อนและสอดไส้ไซรัปคาราเมลหอมเนยน้ำตาลอบเชย'),
(26, 'โดนัทวีแกนเพื่อสุขภาพปราศจากกลูเตน', 'เชฟ นภัสสร', 'เริ่มต้น',   2800, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'โดนัทอบไร้แป้งสาลีและนมเนยไข่ รสสัมผัสนุ่มเบาเพื่อสุขภาพที่ดีเคลือบน้ำตาลมะพร้าวออร์แกนิก'),
(27, 'สตรอว์เบอร์รีชอร์ตเค้กสไตล์ญี่ปุ่น', 'เชฟ ปาริชาต', 'เริ่มต้น',   3500, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?auto=format&fit=crop&w=600&q=80', 'เรียนรู้วิธีอบสปันจ์เค้ก (Sponge Cake) ให้เบาฟูนุ่มสไตล์โตเกียว ประกอบชั้นครีมสดและสตรอว์เบอร์รีรสฉ่ำหวาน'),
(28, 'ช็อกโกแลตมูสลาวาและสตรอว์เบอร์รี', 'เชฟ พงศธร', 'ระดับกลาง', 3300, 12, 'เค้กและขนมหวาน',     '🧁', 'https://images.unsplash.com/photo-1606313564200-e75d5e30476c?auto=format&fit=crop&w=600&q=80', 'ทำเค้กลาวาช็อกโกแลตอุ่นๆ ไส้ไหล คู่กับมูสเบลเยียมช็อกโกแลตเนื้อเนียน และผลสตรอว์เบอร์รีสด'),
(29, 'เค้กแครอทครีมชีสและถั่วพีแคน', 'เชฟ ปาริชาต', 'เริ่มต้น',   2900, 12, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?auto=format&fit=crop&w=600&q=80', 'เค้กแครอทเนื้อชุ่มชื้นอัดแน่นด้วยวอลนัทและลูกเกด ปาดหน้าครีมชีสรสเปรี้ยวหวานมัน ตกแต่งด้วยถั่วพีแคนคั่ว'),
(30, 'เค้กเลมอนบลูเบอร์รีป๊อปปี้ซีด', 'เชฟ ปาริชาต', 'เริ่มต้น',   3100, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?auto=format&fit=crop&w=600&q=80', 'เค้กเนยสดเลมอนผสมเม็ดป๊อปปี้ซีด เคี้ยวกรุบกรอบ สอดไส้ซอสบลูเบอร์รีป่าโฮมเมดราดไอซิ่งเกลซเลมอนรสเปรี้ยวหวานสะใจ'),
(31, 'ทีรามิสุสไตล์อิตาเลียนดั้งเดิม', 'เชฟ พงศธร', 'ระดับกลาง', 3400, 12, 'เค้กและขนมหวาน',     '🧁', 'https://images.unsplash.com/photo-1571877227200-a0d98ea607e9?auto=format&fit=crop&w=600&q=80', 'ทำทีรามิสุแสนอร่อยตามสูตรอิตาลีดั้งเดิม ตั้งแต่ทำเลดี้ฟิงเกอร์เอง ซึมซับกาแฟเอสเพรสโซ่เข้มข้นสลับชั้นมาสคาร์โปนครีมสด'),
(32, 'เค้กเรดเวลเวตพรีเมียมบัตเตอร์ครีม', 'เชฟ ปาริชาต', 'ระดับกลาง', 3200, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?auto=format&fit=crop&w=600&q=80', 'เค้กกำมะหยี่สีแดงรสโกโก้อ่อนๆ สลับชั้นครีมชีสฟรอสติ้งเนียนหนานุ่ม ตกแต่งเค้กให้สวยหรูแนววิคตอเรียน'),
(33, 'นิวยอร์กชีสเค้กซอสสตรอว์เบอร์รี', 'เชฟ ปาริชาต', 'ระดับสูง',  3600, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1524351199679-46cddf530c04?auto=format&fit=crop&w=600&q=80', 'เจาะลึกเทคนิคการอบชีสเค้กแบบนิวยอร์กสตูดิโอให้หน้าเรียบเนียน เนื้อแน่นนุ่มละมุนลิ้น ราดด้วยซอสสตรอว์เบอร์รีป่ารสเปรี้ยวหวานตัดเลี่ยน'),
(34, 'ชูครีมและเอแคลร์ไส้คัสตาร์ด', 'เชฟ ปาริชาต', 'เริ่มต้น',   3000, 12, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1608198093002-ad4e005484ec?auto=format&fit=crop&w=600&q=80', 'ฝึกทำแป้งพัฟชู (Choux Pastry) ให้ฟูกลวงสวย ทำครีมคัสตาร์ดกลิ่นวานิลลาฝักแท้ บีบไส้ชูครีมและราดช็อกโกแลตบนหน้าเอแคลร์'),
(35, 'มิลเฟยพัฟพาสทรีและครีมคัสตาร์ด', 'เชฟ พงศธร', 'ระดับสูง',  3700, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1608198093002-ad4e005484ec?auto=format&fit=crop&w=600&q=80', 'ท้าทายฝีมือกับ Mille-Feuille การพับแป้งพัฟให้บางเฉียบกรอบกรุบเป็นร้อยชั้น สอดสลับชั้นครีมมัสลินวานิลลาหอมหวานหรูหรา'),
(36, 'คานเล่สไตล์บอร์โดและเหล้ารัม', 'เชฟ พงศธร', 'ระดับสูง',  3200, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1608198093002-ad4e005484ec?auto=format&fit=crop&w=600&q=80', 'ฝึกทำ Canelés ขนมฝรั่งเศสโบราณ อบในพิมพ์ทองแดงเคลือบไขผึ้งแท้ (Beeswax) ให้ผิวเกรียมหอมคาราเมลด้านนอก เนื้อในนุ่มฉ่ำหอมเหล้ารัมและวานิลลา'),
(37, 'ฟินันเซียและมาดแลนเนยสีน้ำตาล', 'เชฟ ปาริชาต', 'เริ่มต้น',   2900, 12, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1608198093002-ad4e005484ec?auto=format&fit=crop&w=600&q=80', 'หัดเคี่ยวเนยสีน้ำตาล (Beurre Noisette) อบขนมฝรั่งเศสชิ้นจิ๋วทรงเปลือกหอยและแท่งทองให้ฟูนุ่มหอมกลิ่นถั่วคั่วตามสูตรดั้งเดิม'),
(38, 'คลาสสิกแอปเปิ้ลทาร์ตตาแต็ง', 'เชฟ พงศธร', 'ระดับกลาง', 3300, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1519915028121-7d3463d20b13?auto=format&fit=crop&w=600&q=80', 'ทำทาร์ตแอปเปิ้ลกลับหัวสไตล์ฝรั่งเศสโบราณ (Tarte Tatin) นำแอปเปิ้ลไปเคี่ยวคาราเมลก่อนหุ้มด้วยแป้งพายกรอบเหลืองอร่อย'),
(39, 'ขนมปังควิญอามานเนยเค็มพรีเมียม', 'เชฟ พงศธร', 'ระดับสูง',  3600, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1555507036-ab1f4038808a?auto=format&fit=crop&w=600&q=80', 'ห่อพับเนยเค็ม (Kouign-Amann) และน้ำตาลให้สลับร้อยชั้น สปริงเนยเยิ้มผิวเคลือบคาราเมลกรอบแสนดึงดูดใจ'),
(40, 'พัฟพาสทรีไส้แอปเปิ้ลฝรั่งเศส', 'เชฟ พงศธร', 'ระดับกลาง', 3100, 12, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1608198093002-ad4e005484ec?auto=format&fit=crop&w=600&q=80', 'อบพายแป้งพัฟพาสทรีสอดไส้แอปเปิ้ลซอสบดหอมหวาน (Chausson aux Pommes) สลักลายดอกไม้สวยงามแบบดั้งเดิม');
